```

Changes:
1. Import `getLastSeenUrl`, `setLastSeenUrl` from `./last-seen-urls.js` at the top of background-message-handlers.ts.

2. Replace lines 639-644 with:
```typescript
    // Fallback 1: plugin-declared homepage
    if (meta.homepage) {
      const newTab = await chrome.tabs.create({ url: meta.homepage });
      return { opened: true, tabId: newTab.id };
    }

    // Fallback 2: last-seen URL (persisted from previous sessions)
    const lastUrl = await getLastSeenUrl(pluginName);
