import { describe, test, expect, vi, beforeEach } from 'vitest';
import { getLastSeenUrl, setLastSeenUrl, loadLastSeenUrlsFromStorage, _resetForTesting } from './last-seen-urls.js';

let mockStorage: Record<string, unknown> = {};
